{
  "sentences": [
    {
      "text": "這個便利商店有賣雨傘嗎？",
      "pinyin": "Zhège biànlì shāngdiàn yǒu mài yǔsǎn ma?",
      "pinyin_numeric": "zhe4 ge4 bian4 li4 shang1 dian4 you3 mai4 yu3 san3 ma0",
      "translation_en": "Does this convenience store sell umbrellas?",
      "translation_ko": "이 편의점에서 우산을 팔고 있나요?"
    },
    {
      "text": "那個飯糰要加熱嗎？",
      "pinyin": "Nàge fàntuán yào jiārè ma?",
      "pinyin_numeric": "na4 ge4 fan4 tuan2 yao4 jia1 re4 ma0",
      "translation_en": "Does that rice ball need to be heated?",
      "translation_ko": "그 주먹밥은 데워야 하나요?"
    },
    {
      "text": "這個三明治多少錢？",
      "pinyin": "Zhège sānmíngzhì duōshao qián?",
      "pinyin_numeric": "zhe4 ge4 san1 ming2 zhi4 duo1 shao3 qian2",
      "translation_en": "How much is this sandwich?",
      "translation_ko": "이 샌드위치는 얼마인가요?"
    },
    {
      "text": "那個茶葉蛋是特價的嗎？",
      "pinyin": "Nàge cháyèdàn shì tèjià de ma?",
      "pinyin_numeric": "na4 ge4 cha2 ye4 dan4 shi4 te4 jia4 de0 ma0",
      "translation_en": "Is that tea egg on sale?",
      "translation_ko": "그 차가운 계란은 특가인가요?"
    },
    {
      "text": "這個環保袋要多少錢？",
      "pinyin": "Zhège huánbǎo dài yào duōshao qián?",
      "pinyin_numeric": "zhe4 ge4 huan2 bao3 dai4 yao4 duo1 shao3 qian2",
      "translation_en": "How much is this eco-friendly bag?",
      "translation_ko": "이 친환경 봉투는 얼마인가요?"
    },
    {
      "text": "那個充電線可以刷卡嗎？",
      "pinyin": "Nàge chōngdiànxiàn kěyǐ shuākǎ ma?",
      "pinyin_numeric": "na4 ge4 chong1 dian4 xian4 ke3 yi3 shua1 ka3 ma0",
      "translation_en": "Can I pay by card for that charging cable?",
      "translation_ko": "그 충전 케이블은 카드로 결제할 수 있나요?"
    },
    {
      "text": "這個便當要微波加熱嗎？",
      "pinyin": "Zhège biàndāng yào wēibō jiārè ma?",
      "pinyin_numeric": "zhe4 ge4 bian4 dang1 yao4 wei1 bo1 jia1 re4 ma0",
      "translation_en": "Does this bento need to be microwaved?",
      "translation_ko": "이 도시락은 전자레인지에 데워야 하나요?"
    },
    {
      "text": "那個口罩有特價嗎？",
      "pinyin": "Nàge kòuzhào yǒu tèjià ma?",
      "pinyin_numeric": "na4 ge4 kou4 zhao4 you3 te4 jia4 ma0",
      "translation_en": "Is that mask on sale?",
      "translation_ko": "그 마스크는 특가인가요?"
    },
    {
      "text": "這個泡麵跟那個餅乾總共多少錢？",
      "pinyin": "Zhège pàomiàn gēn nàge bǐnggān zǒnggòng duōshao qián?",
      "pinyin_numeric": "zhe4 ge4 pao4 mian4 gen1 na4 ge4 bing3 gan1 zong3 gong4 duo1 shao3 qian2",
      "translation_en": "How much are this instant noodle and that cookie together?",
      "translation_ko": "이 라면과 그 과자는 총 얼마인가요?"
    },
    {
      "text": "那個電池需要買一送一嗎？",
      "pinyin": "Nàge diànchí xūyào mǎi yī sòng yī ma?",
      "pinyin_numeric": "na4 ge4 dian4 chi2 xu1 yao4 mai3 yi1 song4 yi1 ma0",
      "translation_en": "Is that battery buy-one-get-one-free?",
      "translation_ko": "그 배터리는 하나 사면 하나를 공짜로 주나요?"
    }
  ]
}
